    public void update()
    {
        if(this.UBSConducteurTravaux)
        {
            HcmWorker hcmWorker = HcmWorker::findByPersonnelNumber(this.UBSConducteurTravaux);

            DimensionAttributeValue dav;

            ttsbegin;
            select firstonly forupdate dav where dav.DisplayValue == this.DimensionValue;
            dav.UBSConducteurTravaux = hcmWorker.RecId;
            dav.update();
            ttscommit;
        }
        next update();
    }
